import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handle user input by encoding it
        PrintWriter out = new PrintWriter("output.html");
        out.println("<html>");
        out.println("<head><title>XSS Fixed Example</title></head>");
        out.println("<body>");
        out.println("<h1>User Input: " + Encode.forHtml(userInput) + "</h1>");
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
